  1→import { generateId } from './ids';
  2→import { WALL_THICKNESS, WALL_HEIGHT, DOOR_WIDTH, DOOR_HEIGHT, DOOR_SILL_HEIGHT, WINDOW_WIDTH, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT, COLUMN_WIDTH, COLUMN_DEPTH, BEAM_WIDTH, BEAM_DEPTH, STAIR_WIDTH, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, SLAB_THICKNESS, SLAB_ELEVATION, SECTION_DEPTH, ROOM_COLOR, DIMENSION_DEFAULT_OFFSET } from './defaults';
  3→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
  4→
  5→export function createProject(name = 'Untitled Project') {
  6→  return {
  7→    id: generateId('proj'),
  8→    name,
  9→    createdAt: new Date().toISOString(),
 10→    updatedAt: new Date().toISOString(),
 11→    floors: [createFloor('Ground Floor', 0)],
 12→    sheets: [],
 13→    version: 1,
 14→  };
 15→}
 16→
 17→export function createFloor(name = 'Floor', level = 0) {
 18→  return {
 19→    id: generateId('floor'),
 20→    name,
 21→    level,
 22→    walls: [],
 23→    rooms: [],
 24→    doors: [],
 25→    windows: [],
 26→    columns: [],
 27→    beams: [],
 28→    stairs: [],
 29→    annotations: [],
 30→    annotationSettings: createAnnotationSettings(),
 31→    slabs: [],
 32→    sectionCuts: [],
 33→  };
 34→}
 35→
 36→export function nextSectionLabel(existingCuts = []) {
 37→  const usedLetters = new Set(
 38→    existingCuts
 39→      .map(c => {
 40→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 41→        return match ? match[1] : null;
 42→      })
 43→      .filter(Boolean)
 44→  );
 45→  for (let i = 0; i < 26; i++) {
 46→    const letter = String.fromCharCode(65 + i);
 47→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 48→  }
 49→  return `Section ${existingCuts.length + 1}`;
 50→}
 51→
 52→export function createAnnotationSettings(overrides = {}) {
 53→  return {
 54→    showWallDimensions: overrides.showWallDimensions ?? true,
 55→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 56→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 57→    showObjectTags: overrides.showObjectTags ?? true,
 58→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 59→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 60→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 61→  };
 62→}
 63→
 64→export function createLinearDimensionAnnotation(startPoint, endPoint, options = {}) {
 65→  return {
 66→    id: generateId('anno'),
 67→    type: 'dimension',
 68→    mode: options.mode ?? 'aligned',
 69→    startPoint: { x: startPoint.x, y: startPoint.y },
 70→    endPoint: { x: endPoint.x, y: endPoint.y },
 71→    offset: options.offset ?? DIMENSION_DEFAULT_OFFSET,
 72→    textOverride: options.textOverride ?? '',
 73→  };
 74→}
 75→
 76→export function createWall(start, end, thickness = WALL_THICKNESS, options = {}) {
 77→  return {
 78→    id: generateId('wall'),
 79→    start: { x: start.x, y: start.y },
 80→    end: { x: end.x, y: end.y },
 81→    thickness,
 82→    height: options.height ?? WALL_HEIGHT,
 83→    startAttachment: options.startAttachment ?? null,
 84→    endAttachment: options.endAttachment ?? null,
 85→  };
 86→}
 87→
 88→export function createDoor(wallId, offset, width = DOOR_WIDTH, openDirection = 'left', type = 'swing') {
 89→  return {
 90→    id: generateId('door'),
 91→    wallId,
 92→    offset,
 93→    width,
 94→    height: DOOR_HEIGHT,
 95→    sillHeight: DOOR_SILL_HEIGHT,
 96→    openDirection,
 97→    type,
 98→  };
 99→}
100→
101→export function createWindow(wallId, offset, width = WINDOW_WIDTH, type = 'standard', openDirection = 'left') {
102→  return {
103→    id: generateId('win'),
104→    wallId,
105→    offset,
106→    width,
107→    height: WINDOW_HEIGHT,
108→    sillHeight: WINDOW_SILL_HEIGHT,
109→    type,
110→    openDirection,
