113→
114→export function createColumn(x, y, width = COLUMN_WIDTH, depth = COLUMN_DEPTH, options = {}) {
115→  return {
116→    id: generateId('col'),
117→    x, y, width, depth,
118→    height: options.height ?? 3000,
119→    rotation: options.rotation ?? 0,
120→    type: options.type ?? 'rectangular',
121→    name: options.name ?? '',
122→    showLabel: options.showLabel ?? false,
