139→    id: generateId('slab'),
140→    floorId,
141→    boundaryPoints: boundaryPoints.map(point => ({ x: point.x, y: point.y })),
142→    thickness,
143→    elevation,
144→    name: options.name ?? '',
145→    type: options.type ?? '',
146→  };
147→}
148→
149→export function createStair(startPoint, width = STAIR_WIDTH, numberOfRisers = STAIR_RISERS, riserHeight = STAIR_RISER_HEIGHT, treadDepth = STAIR_TREAD_DEPTH, direction = { angle: 0 }, floorRelation = {}) {
150→  return {
151→    id: generateId('stair'),
152→    startPoint: { x: startPoint.x, y: startPoint.y },
153→    width,
154→    numberOfRisers,
155→    riserHeight,
156→    treadDepth,
157→    direction: {
158→      angle: direction?.angle ?? 0,
159→    },
160→    floorRelation: {
161→      fromFloorId: floorRelation.fromFloorId ?? null,
162→      toFloorId: floorRelation.toFloorId ?? null,
163→    },
164→  };
165→}
166→
167→export function createSectionCut(startPoint, endPoint, options = {}) {
168→  return {
169→    id: generateId('section'),
170→    startPoint: { x: startPoint.x, y: startPoint.y },
171→    endPoint: { x: endPoint.x, y: endPoint.y },
172→    depth: options.depth ?? SECTION_DEPTH,
173→    label: options.label ?? 'Section A-A',
174→    direction: options.direction ?? 1,
175→  };
176→}
177→
178→export function createRoom(name = 'Room', points = [], color = ROOM_COLOR) {
179→  const area = polygonArea(points);
180→  const centroid = points.length >= 3 ? polygonCentroid(points) : { x: 0, y: 0 };
181→  return {
182→    id: generateId('room'),
183→    name,
184→    points: points.map(p => ({ x: p.x, y: p.y })),
185→    labelPosition: { ...centroid },
186→    color,
187→    area,
188→  };
189→}
