  7→
  8→const DOOR_INSERT_THICKNESS_MIN = 35;
  9→const DOOR_INSERT_THICKNESS_MAX = 70;
 10→const WINDOW_INSERT_THICKNESS_MIN = 45;
 11→const WINDOW_INSERT_THICKNESS_MAX = 90;
 12→
 13→function createBoundsFromPoints(points, baseElevation, topElevation) {
 14→  if (!points?.length) {
 15→    return {
 16→      minX: 0,
 17→      maxX: 0,
 18→      minY: 0,
 19→      maxY: 0,
 20→      minElevation: baseElevation,
 21→      maxElevation: topElevation,
 22→    };
 23→  }
 24→
 25→  return {
 26→    minX: Math.min(...points.map((point) => point.x)),
 27→    maxX: Math.max(...points.map((point) => point.x)),
 28→    minY: Math.min(...points.map((point) => point.y)),
 29→    maxY: Math.max(...points.map((point) => point.y)),
 30→    minElevation: baseElevation,
 31→    maxElevation: topElevation,
 32→  };
 33→}
 34→
 35→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 36→  const topElevation = baseElevation + height;
 37→  return {
 38→    id,
 39→    kind,
 40→    geometry: 'prism',
 41→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 42→    baseElevation,
 43→    height,
 44→    materialKey: metadata.materialKey || kind,
 45→    metadata,
 46→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 47→  };
 48→}
 49→
 50→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 51→  const outline = wallOutline({
 52→    start: { x: startPoint.x, y: startPoint.y },
 53→    end: { x: endPoint.x, y: endPoint.y },
 54→    thickness: width,
 55→  });
 56→  const direction = wallDirection({
 57→    start: { x: startPoint.x, y: startPoint.y },
 58→    end: { x: endPoint.x, y: endPoint.y },
 59→  });
 60→  const topElevation = baseElevation + height;
 61→
 62→  return {
 63→    id,
 64→    kind,
 65→    geometry: 'box',
 66→    center: {
 67→      x: (startPoint.x + endPoint.x) / 2,
 68→      y: (startPoint.y + endPoint.y) / 2,
 69→    },
 70→    size: {
 71→      x: wallLength({ start: startPoint, end: endPoint }),
 72→      y: height,
 73→      z: width,
 74→    },
 75→    rotation: Math.atan2(direction.y, direction.x),
 76→    baseElevation,
 77→    materialKey: metadata.materialKey || kind,
 78→    metadata,
 79→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 80→  };
 81→}
 82→
 83→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 84→  const halfX = size.x / 2;
 85→  const halfZ = size.z / 2;
 86→  const cos = Math.cos(rotation);
 87→  const sin = Math.sin(rotation);
 88→  const corners = [
 89→    { x: -halfX, y: -halfZ },
 90→    { x: halfX, y: -halfZ },
 91→    { x: halfX, y: halfZ },
 92→    { x: -halfX, y: halfZ },
 93→  ].map((point) => ({
 94→    x: center.x + (point.x * cos - point.y * sin),
 95→    y: center.y + (point.x * sin + point.y * cos),
 96→  }));
 97→
 98→  return {
 99→    id,
100→    kind,
101→    geometry: 'box',
102→    center: { x: center.x, y: center.y },
103→    size,
104→    rotation,
105→    baseElevation,
106→    materialKey: metadata.materialKey || kind,
107→    metadata,
108→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
109→  };
110→}
