217→function getInsertThickness(kind, wallThickness) {
218→  if (kind === 'door') {
219→    return Math.max(
220→      DOOR_INSERT_THICKNESS_MIN,
221→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
222→    );
223→  }
224→
225→  return Math.max(
226→    WINDOW_INSERT_THICKNESS_MIN,
227→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
228→  );
229→}
