 54→function projectReducer(state, action) {
 55→  switch (action.type) {
 56→    case 'PROJECT_NEW':
 57→      return {
 58→        project: action.project,
 59→        isDirty: false,
 60→        lastSavedAt: null,
 61→        savedSnapshot: snapshotProject(action.project),
 62→        history: [],
 63→        future: [],
 64→      };
 65→
 66→    case 'PROJECT_LOAD':
 67→      return {
 68→        project: action.project,
 69→        isDirty: false,
 70→        lastSavedAt: action.savedAt || null,
 71→        savedSnapshot: snapshotProject(action.project),
 72→        history: [],
 73→        future: [],
 74→      };
 75→
 76→    case 'PROJECT_SET_NAME':
 77→      return applyProjectUpdate(state, {
 78→        ...state.project,
 79→        name: action.name,
 80→        updatedAt: new Date().toISOString(),
 81→      });
 82→
 83→    case 'SHEET_ADD':
 84→      return applyProjectUpdate(state, {
