 27→function buildWallRects(floor, view) {
 28→  return (floor.walls || [])
 29→    .map((wall) => {
 30→      const renderData = getWallRenderData(wall, floor.columns || []);
 31→      return createSceneRect(
 32→        `wall-elev-${wall.id}`,
 33→        'wall',
