  1→import { getSlabBottomLevel } from '@/elevations/slab';
  2→import { getBeamRenderData } from '@/geometry/beamGeometry';
  3→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
  4→import { getStairRenderData } from '@/geometry/stairGeometry';
  5→import { wallDirection, wallLength, wallOutline } from '@/geometry/wallGeometry';
  6→import { buildWallPreviewContexts, buildWallSolidSegments } from './wallPreviewContext';
  7→
  8→const DOOR_INSERT_THICKNESS_MIN = 35;
  9→const DOOR_INSERT_THICKNESS_MAX = 70;
 10→const WINDOW_INSERT_THICKNESS_MIN = 45;
 11→const WINDOW_INSERT_THICKNESS_MAX = 90;
 12→
 13→function createBoundsFromPoints(points, baseElevation, topElevation) {
 14→  if (!points?.length) {
 15→    return {
 16→      minX: 0,
 17→      maxX: 0,
 18→      minY: 0,
 19→      maxY: 0,
 20→      minElevation: baseElevation,
 21→      maxElevation: topElevation,
 22→    };
 23→  }
 24→
 25→  return {
 26→    minX: Math.min(...points.map((point) => point.x)),
 27→    maxX: Math.max(...points.map((point) => point.x)),
 28→    minY: Math.min(...points.map((point) => point.y)),
 29→    maxY: Math.max(...points.map((point) => point.y)),
 30→    minElevation: baseElevation,
 31→    maxElevation: topElevation,
 32→  };
 33→}
 34→
 35→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 36→  const topElevation = baseElevation + height;
 37→  return {
 38→    id,
 39→    kind,
 40→    geometry: 'prism',
 41→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 42→    baseElevation,
 43→    height,
 44→    materialKey: metadata.materialKey || kind,
 45→    metadata,
 46→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 47→  };
 48→}
 49→
 50→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 51→  const outline = wallOutline({
 52→    start: { x: startPoint.x, y: startPoint.y },
 53→    end: { x: endPoint.x, y: endPoint.y },
 54→    thickness: width,
 55→  });
 56→  const direction = wallDirection({
 57→    start: { x: startPoint.x, y: startPoint.y },
 58→    end: { x: endPoint.x, y: endPoint.y },
 59→  });
 60→  const topElevation = baseElevation + height;
 61→
 62→  return {
 63→    id,
 64→    kind,
 65→    geometry: 'box',
 66→    center: {
 67→      x: (startPoint.x + endPoint.x) / 2,
 68→      y: (startPoint.y + endPoint.y) / 2,
 69→    },
 70→    size: {
 71→      x: wallLength({ start: startPoint, end: endPoint }),
 72→      y: height,
 73→      z: width,
 74→    },
 75→    rotation: Math.atan2(direction.y, direction.x),
 76→    baseElevation,
 77→    materialKey: metadata.materialKey || kind,
 78→    metadata,
 79→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 80→  };
 81→}
 82→
 83→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 84→  const halfX = size.x / 2;
 85→  const halfZ = size.z / 2;
 86→  const cos = Math.cos(rotation);
 87→  const sin = Math.sin(rotation);
 88→  const corners = [
 89→    { x: -halfX, y: -halfZ },
 90→    { x: halfX, y: -halfZ },
 91→    { x: halfX, y: halfZ },
 92→    { x: -halfX, y: halfZ },
 93→  ].map((point) => ({
 94→    x: center.x + (point.x * cos - point.y * sin),
 95→    y: center.y + (point.x * sin + point.y * cos),
 96→  }));
 97→
 98→  return {
 99→    id,
100→    kind,
101→    geometry: 'box',
102→    center: { x: center.x, y: center.y },
103→    size,
104→    rotation,
105→    baseElevation,
106→    materialKey: metadata.materialKey || kind,
107→    metadata,
108→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
109→  };
110→}
111→
112→function createStairDescriptor(stair, floorLevel, floorId) {
113→  const renderData = getStairRenderData(stair);
114→  if (!renderData?.outline?.length) return null;
115→
116→  return {
117→    id: stair.id,
118→    kind: 'stair',
119→    geometry: 'stair',
120→    startPoint: { ...stair.startPoint },
121→    width: stair.width,
122→    numberOfRisers: stair.numberOfRisers,
123→    riserHeight: stair.riserHeight,
124→    treadDepth: stair.treadDepth,
125→    angle: renderData.angle,
126→    baseElevation: floorLevel,
127→    materialKey: 'stair',
128→    metadata: {
129→      sourceId: stair.id,
130→      floorId,
131→    },
132→    bounds: createBoundsFromPoints(
133→      renderData.outline,
134→      floorLevel,
135→      floorLevel + renderData.totalRise
136→    ),
137→  };
138→}
139→
140→function buildWallObjects(wallContexts) {
141→  return wallContexts.flatMap((context) => (
142→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
143→      segment.id,
144→      'wall',
145→      segment.startPoint,
146→      segment.endPoint,
147→      segment.thickness,
148→      segment.baseElevation,
149→      segment.topElevation - segment.baseElevation,
150→      {
151→        sourceId: segment.wallId,
152→        floorId: segment.floorId,
153→        wallId: segment.wallId,
154→      }
155→    ))
156→  ));
157→}
158→
159→function buildSlabObjects(floor) {
160→  return (floor.slabs || [])
161→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
162→    .map(slab => createPrismDescriptor(
163→      slab.id,
164→      'slab',
165→      slab.boundaryPoints,
166→      getSlabBottomLevel(slab),
167→      slab.thickness ?? 0,
168→      {
169→        sourceId: slab.id,
170→        floorId: floor.id,
171→      }
172→    ));
173→}
174→
175→function buildColumnObjects(floor, floorLevel) {
176→  return (floor.columns || []).map((column) => createBoxDescriptor(
177→    column.id,
178→    'column',
179→    { x: column.x, y: column.y },
180→    {
181→      x: column.width,
182→      y: column.height,
183→      z: column.depth,
184→    },
185→    floorLevel,
186→    (column.rotation || 0) * Math.PI / 180,
187→    {
188→      sourceId: column.id,
189→      floorId: floor.id,
190→    }
191→  ));
192→}
193→
194→function buildBeamObjects(floor) {
195→  return (floor.beams || [])
196→    .map((beam) => {
197→      const renderData = getBeamRenderData(beam, floor.columns || []);
198→      if (!renderData) return null;
199→
200→      return createLinearBoxDescriptor(
201→        beam.id,
202→        'beam',
203→        renderData.start,
204→        renderData.end,
205→        beam.width,
206→        beam.floorLevel - beam.depth,
207→        beam.depth,
208→        {
209→          sourceId: beam.id,
210→          floorId: floor.id,
211→        }
212→      );
213→    })
214→    .filter(Boolean);
215→}
216→
217→function getInsertThickness(kind, wallThickness) {
218→  if (kind === 'door') {
219→    return Math.max(
220→      DOOR_INSERT_THICKNESS_MIN,
221→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
222→    );
223→  }
224→
225→  return Math.max(
226→    WINDOW_INSERT_THICKNESS_MIN,
227→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
228→  );
229→}
230→
231→function createOpeningInsertDescriptor(opening) {
232→  return createBoxDescriptor(
233→    opening.id,
234→    opening.kind,
235→    opening.centerPoint,
236→    {
237→      x: opening.visibleWidth,
238→      y: opening.visibleHeight,
239→      z: getInsertThickness(opening.kind, opening.wallThickness),
240→    },
241→    opening.visibleBaseElevation,
242→    opening.angle,
243→    {
244→      sourceId: opening.sourceId,
245→      floorId: opening.metadata.floorId,
246→      wallId: opening.wallId,
247→      openingKind: opening.kind,
248→    }
249→  );
250→}
251→
252→function buildDoorObjects(wallContexts) {
253→  return wallContexts
254→    .flatMap((context) => context.openings)
255→    .filter((opening) => opening.kind === 'door')
256→    .map((opening) => createOpeningInsertDescriptor(opening));
257→}
258→
259→function buildWindowObjects(wallContexts) {
260→  return wallContexts
261→    .flatMap((context) => context.openings)
262→    .filter((opening) => opening.kind === 'window')
263→    .map((opening) => createOpeningInsertDescriptor(opening));
264→}
265→
266→function buildStairObjects(floor, floorLevel) {
267→  return (floor.stairs || [])
268→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id))
269→    .filter(Boolean);
270→}
271→
272→export function buildFloorPreviewObjects(floor) {
273→  const floorLevel = floor?.level ?? 0;
274→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
275→
276→  return [
277→    ...buildSlabObjects(floor),
278→    ...buildWallObjects(wallContexts),
279→    ...buildColumnObjects(floor, floorLevel),
280→    ...buildBeamObjects(floor),
281→    ...buildStairObjects(floor, floorLevel),
282→    ...buildDoorObjects(wallContexts),
283→    ...buildWindowObjects(wallContexts),
284→  ];
285→}
