144→function computeSceneBounds(elements = [], baseLevel = 0) {
145→  if (!elements.length) {
146→    return {
147→      minX: -1000,
148→      maxX: 1000,
149→      minZ: baseLevel,
150→      maxZ: baseLevel + 3000,
151→    };
152→  }
153→
154→  return {
155→    minX: Math.min(...elements.map((element) => element.left)),
156→    maxX: Math.max(...elements.map((element) => element.right)),
157→    minZ: Math.min(baseLevel, ...elements.map((element) => element.bottom)),
158→    maxZ: Math.max(...elements.map((element) => element.top)),
159→  };
160→}
