162→export function buildElevationScene(floor, viewMode) {
163→  if (!floor) return null;
164→
165→  const view = getElevationView(viewMode);
166→  const elements = [
167→    ...buildWallRects(floor, view),
168→    ...buildSlabRects(floor, view),
169→    ...buildColumnRects(floor, view),
170→    ...buildBeamRects(floor, view),
171→    ...buildStairRects(floor, view),
172→    ...buildDoorRects(floor, view),
173→    ...buildWindowRects(floor, view),
174→  ].sort((a, b) => b.depth - a.depth);
175→
176→  return {
177→    viewKey: view.key,
178→    title: view.label,
179→    elements,
180→    bounds: computeSceneBounds(elements, floor.level ?? 0),
181→    groundLevel: floor.level ?? 0,
182→  };
183→}
