### 2. WALL PREVIEW CONTEXT (Position Calculation)

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/wallPreviewContext.js`

The system builds `wallPreviewContext` objects that contain opening descriptors with calculated positions. Key function:

```javascript
function buildOpeningDescriptor(kind, source, context) {
  // Maps door/window model → wall-relative coordinates
  // Handles clipping to visible portion of wall

  return {
    id: source.id,
    kind: "door" | "window",
    wallId: context.wall.id,
    sourceId: source.id,
    angle: wallAngle(context.renderWall),
    wallThickness: context.renderWall.thickness,
    width: source.width,
    height: source.height ?? 0,
    sillHeight: source.sillHeight ?? 0,
    startAlong, endAlong, centerAlong,          // Positions along wall length
    visibleWidth, visibleHeight,                // Clipped to visible wall section
    visibleBaseElevation, visibleTopElevation,  // Elevation range
    startPoint, endPoint, centerPoint,          // World coordinates
    outline: wallOutline(...),                  // 2D footprint
    metadata: { wallId, floorId, sourceStart/EndAlong, clipped... }
  };
}
```

This context flows through `buildWallPreviewContexts()` which processes all doors and windows per wall.

---

### 3. OBJECT BUILDERS (Descriptor Generation)

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/objectBuilders.js`

**Key functions:**

#### `buildWindowObjects(wallContexts)`
```javascript
function buildWindowObjects(wallContexts) {
  return wallContexts
    .flatMap((context) => context.openings)
    .filter((opening) => opening.kind === 'window')
    .map((opening) => createOpeningInsertDescriptor(opening));
}
```

#### `buildDoorObjects(wallContexts)`
```javascript
function buildDoorObjects(wallContexts) {
  return wallContexts
    .flatMap((context) => context.openings)
    .filter((opening) => opening.kind === 'door')
    .map((opening) => createOpeningInsertDescriptor(opening));
}
```

Both use the same descriptor builder:

#### `createOpeningInsertDescriptor(opening)` - CRITICAL FUNCTION
```javascript
function createOpeningInsertDescriptor(opening) {
  return createBoxDescriptor(
    opening.id,
    opening.kind,                               // "door" or "window"
    opening.centerPoint,                        // XY position on wall
    {
      x: opening.visibleWidth,                  // Width of visible opening
      y: opening.visibleHeight,                 // Height of visible opening
      z: getInsertThickness(opening.kind, opening.wallThickness),  // Thickness
    },
    opening.visibleBaseElevation,               // Elevation in world space
    opening.angle,                              // Rotation angle
    {
      sourceId: opening.sourceId,
      floorId: opening.metadata.floorId,
      wallId: opening.wallId,
      openingKind: opening.kind,                // Metadata preserves door/window type
    }
  );
}
```

#### `getInsertThickness(kind, wallThickness)` - THICKNESS LOGIC
```javascript
function getInsertThickness(kind, wallThickness) {
  if (kind === 'door') {
    return Math.max(
      DOOR_INSERT_THICKNESS_MIN,                // 35mm
      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)  // 35-70mm
    );
  }

  return Math.max(
    WINDOW_INSERT_THICKNESS_MIN,                // 45mm
    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)  // 45-90mm
  );
}
```

**Key insight:** Door/window thickness scales with wall thickness:
- **Doors:** 22% of wall thickness, clamped 35-70mm
- **Windows:** 32% of wall thickness, clamped 45-90mm

#### `createBoxDescriptor(id, kind, center, size, baseElevation, rotation, metadata)`
Creates a box geometry descriptor with:
- `geometry: 'box'`
- `kind: 'door' | 'window'`
- `materialKey: 'door' | 'window'` (used for material lookup)
- `metadata.openingKind` - preserves the door/window type from the source object

The descriptor hierarchy for final 3D scene:
```javascript
export function buildFloorPreviewObjects(floor) {
  const wallContexts = buildWallPreviewContexts(floor, floorLevel);

  return [
    ...buildSlabObjects(floor),
    ...buildWallObjects(wallContexts),
    ...buildColumnObjects(floor, floorLevel),
    ...buildBeamObjects(floor),
    ...buildStairObjects(floor, floorLevel),
    ...buildDoorObjects(wallContexts),      // Returns box descriptors
    ...buildWindowObjects(wallContexts),    // Returns box descriptors
  ];
}
```

