### 5. THREE.JS MESH CREATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/viewer/buildPreviewObjects.js`

#### `buildPreviewObjectRoot(sceneDescriptor, materialPalette)`

```javascript
export function buildPreviewObjectRoot(sceneDescriptor, materialPalette) {
  const root = new THREE.Group();

  for (const floor of sceneDescriptor.floors) {
    const floorGroup = new THREE.Group();
    floorGroup.name = `floor-${floor.floorId}`;

    for (const descriptor of floor.objects) {
      const object = createObjectForDescriptor(descriptor, materialPalette);
      object.name = descriptor.id;
      object.userData = {
        id: descriptor.id,
        kind: descriptor.kind,                  // 'door' or 'window'
        metadata: descriptor.metadata,
      };
      floorGroup.add(object);
    }

    root.add(floorGroup);
  }

  return root;
}
```

#### `createObjectForDescriptor(descriptor, materialPalette)`

```javascript
function createObjectForDescriptor(descriptor, materialPalette) {
  if (descriptor.geometry === 'prism') {
    return createPrismObject(descriptor, materialPalette);
  }

  if (descriptor.geometry === 'stair') {
    return createStairObject(descriptor, materialPalette);
  }

  return createBoxObject(descriptor, materialPalette);  // Door & window path
}
```

#### `createBoxObject(descriptor, materialPalette)` - DOOR/WINDOW CREATION

```javascript
function createBoxObject(descriptor, materialPalette) {
  // Create raw Three.js box geometry
  const geometry = new THREE.BoxGeometry(
    Math.max(descriptor.size.x, 1),   // Width (along wall)
    Math.max(descriptor.size.y, 1),   // Height (vertical)
    Math.max(descriptor.size.z, 1)    // Thickness (into wall)
  );

  // Apply material from palette by materialKey ('door' or 'window')
  const mesh = new THREE.Mesh(geometry, materialPalette[descriptor.materialKey]);

  // Position: center point + half height in world space
  const center = planPointToWorld(
    descriptor.center,
    descriptor.baseElevation + descriptor.size.y / 2
  );
  mesh.position.copy(center);

  // Rotation around Y axis (vertical)
  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);

  mesh.castShadow = true;
  mesh.receiveShadow = true;

  // Add edge outline
  addOutline(mesh, materialPalette);

  return mesh;
}
```

#### `addOutline(object3d, materialPalette)`

```javascript
function addOutline(object3d, materialPalette) {
  if (!object3d.geometry) return;
  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);  // 20° threshold
  const outline = new THREE.LineSegments(edges, materialPalette.outline);
  object3d.add(outline);
}
```

---

### 6. COORDINATE TRANSFORMATION PIPELINE

**Key functions from `buildPreviewObjects.js`:**

```javascript
function planPointToWorld(point, elevation = 0) {
  // Plan coords (X, Y in mm) → World coords (X, Y, Z in Three.js)
  return new THREE.Vector3(point.x, elevation, point.y);
}

function planAngleToWorldRotation(angle = 0) {
  // Wall angle → Three.js Y-axis rotation
  return -angle;  // Negated for proper handedness
}
```

**Elevation system:**
- Model space: Y = vertical elevation (mm)
- Three.js space: Y = vertical (world up), X = plan X, Z = plan Y
- `baseElevation` from descriptor → mesh Y position
- Mesh height centers at `baseElevation + size.y / 2`

