### 8. SCENE ASSEMBLY ORCHESTRATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/scene/buildPreviewScene.js`

```javascript
export function buildPreviewScene(project, options = {}) {
  const floors = project?.floors || [];
  const activeFloorId = options.activeFloorId ?? floors[0]?.id ?? null;

  const floorDescriptors = floors.map((floor) => {
    const objects = buildFloorPreviewObjects(floor);  // Gets all descriptors
    return {
      floorId: floor.id,
      name: floor.name,
      level: floor.level ?? 0,
      visible: visibleFloorIds.has(floor.id),
      objects,                                        // Contains door/window descriptors
      bounds: boundsFromObjects(objects),             // Calc camera bounds
    };
  });

  return {
    activeFloorId,
    visibleFloorIds: [...visibleFloorIds],
    floors: floorDescriptors,
    bounds,                                           // Used for camera fitting
    defaultTarget: { x, y, z },
    groundLevel,
    hasVisibleObjects,
  };
}
```

---

### 9. REACT INTEGRATION

**File:** `/c/Users/johnm/modular apartment planner/src/three/viewer/ThreePreviewPanel.jsx`

```javascript
export default function ThreePreviewPanel({ project, activeFloorId, className = '' }) {
  // 1. Build scene descriptor (calls buildFloorPreviewObjects → windows & doors included)
  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
    activeFloorId,
    visibleFloorIds: activeFloorId ? [activeFloorId] : [],
  }), [project, activeFloorId]);

  // 2. Create Three.js viewport
  useEffect(() => {
    const viewport = createPreviewViewport(containerRef.current);
    // ... setup
  }, []);

  // 3. Build Three.js objects and render
  useEffect(() => {
    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette);
    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
  }, [sceneDescriptor]);

  return <section>3D preview canvas</section>;
}
```

