  1→import { doorOutlineOnWall } from '@/geometry/wallGeometry';
  2→
  3→function SwingDoor({ door, info }) {
  4→  const flipSign = door.openDirection === 'right' ? -1 : 1;
  5→  const angleDeg = (info.angle * 180) / Math.PI;
  6→
  7→  return (
  8→    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
  9→      <line
 10→        x1={0} y1={0}
 11→        x2={0} y2={flipSign * -door.width}
 12→        stroke="var(--color-wall-fill)"
 13→        strokeWidth={2}
 14→        vectorEffect="non-scaling-stroke"
 15→      />
 16→      <path
 17→        d={`M ${door.width} 0 A ${door.width} ${door.width} 0 0 ${door.openDirection === 'left' ? 1 : 0} 0 ${flipSign * -door.width}`}
 18→        fill="none"
 19→        stroke="var(--color-wall-fill)"
 20→        strokeWidth={1}
 21→        strokeDasharray="4 3"
 22→        vectorEffect="non-scaling-stroke"
 23→      />
 24→    </g>
 25→  );
 26→}
 27→
 28→function DoubleDoor({ door, info }) {
 29→  const angleDeg = (info.angle * 180) / Math.PI;
 30→  const halfWidth = door.width / 2;
 31→
 32→  return (
 33→    <g transform={`translate(${info.center.x},${info.center.y}) rotate(${angleDeg})`}>
 34→      {/* Left leaf */}
 35→      <line
 36→        x1={0} y1={0}
 37→        x2={0} y2={-halfWidth}
 38→        stroke="var(--color-wall-fill)"
 39→        strokeWidth={2}
 40→        vectorEffect="non-scaling-stroke"
 41→      />
 42→      <path
 43→        d={`M ${-halfWidth} 0 A ${halfWidth} ${halfWidth} 0 0 1 0 ${-halfWidth}`}
 44→        fill="none"
 45→        stroke="var(--color-wall-fill)"
 46→        strokeWidth={1}
 47→        strokeDasharray="4 3"
 48→        vectorEffect="non-scaling-stroke"
 49→      />
 50→      {/* Right leaf */}
 51→      <line
 52→        x1={0} y1={0}
 53→        x2={0} y2={halfWidth}
 54→        stroke="var(--color-wall-fill)"
 55→        strokeWidth={2}
 56→        vectorEffect="non-scaling-stroke"
 57→      />
 58→      <path
 59→        d={`M ${halfWidth} 0 A ${halfWidth} ${halfWidth} 0 0 1 0 ${halfWidth}`}
 60→        fill="none"
 61→        stroke="var(--color-wall-fill)"
 62→        strokeWidth={1}
 63→        strokeDasharray="4 3"
 64→        vectorEffect="non-scaling-stroke"
 65→      />
 66→    </g>
 67→  );
 68→}
 69→
 70→function SlidingDoor({ door, info }) {
 71→  const flipSign = door.openDirection === 'right' ? -1 : 1;
 72→  const angleDeg = (info.angle * 180) / Math.PI;
 73→  const arrowY = flipSign * -12;
 74→  const arrowStart = 0.2 * door.width;
 75→  const arrowEnd = 0.8 * door.width;
 76→
 77→  return (
 78→    <g transform={`translate(${info.start.x},${info.start.y}) rotate(${angleDeg})`}>
 79→      {/* Thick panel line */}
 80→      <line
 81→        x1={0} y1={0}
 82→        x2={door.width} y2={0}
 83→        stroke="var(--color-wall-fill)"
 84→        strokeWidth={4}
 85→        vectorEffect="non-scaling-stroke"
 86→      />
 87→      {/* Direction arrow line */}
 88→      <line
 89→        x1={arrowStart} y1={arrowY}
 90→        x2={arrowEnd} y2={arrowY}
 91→        stroke="var(--color-wall-fill)"
 92→        strokeWidth={1}
 93→        vectorEffect="non-scaling-stroke"
 94→      />
 95→      {/* Arrowhead */}
 96→      <polyline
 97→        points={`${arrowEnd - 6},${arrowY - 4} ${arrowEnd},${arrowY} ${arrowEnd - 6},${arrowY + 4}`}
 98→        fill="none"
 99→        stroke="var(--color-wall-fill)"
100→        strokeWidth={1}
101→        vectorEffect="non-scaling-stroke"
102→      />
103→    </g>
104→  );
105→}
