  9→function createSceneRect(id, category, projection, bottom, top, options = {}) {
 10→  if (!projection) return null;
 11→  if (Math.abs(projection.right - projection.left) < 1e-6) return null;
 12→  if (Math.abs(top - bottom) < 1e-6) return null;
 13→
 14→  return {
 15→    id,
 16→    category,
 17→    left: projection.left,
 18→    right: projection.right,
 19→    bottom,
 20→    top,
 21→    depth: projection.depth,
 22→    style: options.style || category,
 23→    sourceId: options.sourceId || null,
 24→  };
 25→}
 26→
 27→function buildWallRects(floor, view) {
 28→  return (floor.walls || [])
 29→    .map((wall) => {
 30→      const renderData = getWallRenderData(wall, floor.columns || []);
 31→      return createSceneRect(
 32→        `wall-elev-${wall.id}`,
 33→        'wall',
 34→        projectPlanPoints(view, renderData.outline),
 35→        floor.level ?? 0,
 36→        (floor.level ?? 0) + (wall.height ?? 0),
 37→        { sourceId: wall.id }
 38→      );
 39→    })
 40→    .filter(Boolean);
 41→}
 42→
 43→function buildSlabRects(floor, view) {
 44→  return (floor.slabs || []).flatMap((slab) => {
 45→    const slabTop = getSlabTopLevel(slab);
 46→    const slabBottom = getSlabBottomLevel(slab);
 47→
 48→    return buildSlabElevationBands(slab, view)
 49→      .map((band) => createSceneRect(
 50→        `slab-elev-${slab.id}-${band.edgeIndex}`,
 51→        'slab',
 52→        band,
 53→        slabBottom,
 54→        slabTop,
 55→        { sourceId: slab.id }
 56→      ))
 57→      .filter(Boolean);
 58→  });
 59→}
 60→
 61→function buildColumnRects(floor, view) {
 62→  return (floor.columns || [])
 63→    .map((column) => createSceneRect(
 64→      `column-elev-${column.id}`,
 65→      'column',
 66→      projectPlanPoints(view, columnOutline(column)),
 67→      floor.level ?? 0,
 68→      (floor.level ?? 0) + column.height,
 69→      { sourceId: column.id }
 70→    ))
 71→    .filter(Boolean);
 72→}
 73→
 74→function buildBeamRects(floor, view) {
 75→  return (floor.beams || [])
 76→    .map((beam) => {
 77→      const renderData = getBeamRenderData(beam, floor.columns || []);
 78→      if (!renderData) return null;
 79→      return createSceneRect(
 80→        `beam-elev-${beam.id}`,
 81→        'beam',
 82→        projectPlanPoints(view, renderData.outline),
 83→        beam.floorLevel - beam.depth,
 84→        beam.floorLevel,
 85→        { sourceId: beam.id }
 86→      );
 87→    })
 88→    .filter(Boolean);
 89→}
 90→
 91→function buildStairRects(floor, view) {
 92→  return (floor.stairs || [])
 93→    .map((stair) => {
 94→      const renderData = getStairRenderData(stair);
 95→      if (!renderData?.outline?.length) return null;
 96→      return createSceneRect(
 97→        `stair-elev-${stair.id}`,
 98→        'stair',
 99→        projectPlanPoints(view, renderData.outline),
100→        floor.level ?? 0,
101→        (floor.level ?? 0) + renderData.totalRise,
102→        { sourceId: stair.id }
103→      );
104→    })
105→    .filter(Boolean);
106→}
