108→function buildDoorRects(floor, view) {
109→  return (floor.doors || [])
110→    .map((door) => {
111→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
112→      if (!wall) return null;
113→      const info = doorOutlineOnWall(wall, door);
114→      return createSceneRect(
115→        `door-elev-${door.id}`,
116→        'door',
117→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
118→        (floor.level ?? 0) + (door.sillHeight ?? 0),
119→        (floor.level ?? 0) + (door.sillHeight ?? 0) + (door.height ?? 0),
120→        { sourceId: door.id }
121→      );
122→    })
123→    .filter(Boolean);
124→}
