126→function buildWindowRects(floor, view) {
127→  return (floor.windows || [])
128→    .map((windowItem) => {
129→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
130→      if (!wall) return null;
131→      const info = windowOutlineOnWall(wall, windowItem);
132→      return createSceneRect(
133→        `window-elev-${windowItem.id}`,
134→        'window',
135→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
136→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0),
137→        (floor.level ?? 0) + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
138→        { sourceId: windowItem.id }
139→      );
140→    })
141→    .filter(Boolean);
142→}
143→
144→function computeSceneBounds(elements = [], baseLevel = 0) {
145→  if (!elements.length) {
146→    return {
147→      minX: -1000,
148→      maxX: 1000,
149→      minZ: baseLevel,
150→      maxZ: baseLevel + 3000,
151→    };
152→  }
153→
154→  return {
155→    minX: Math.min(...elements.map((element) => element.left)),
156→    maxX: Math.max(...elements.map((element) => element.right)),
157→    minZ: Math.min(baseLevel, ...elements.map((element) => element.bottom)),
158→    maxZ: Math.max(...elements.map((element) => element.top)),
159→  };
160→}
